import{_ as n,H as s,f as a,i as o}from"./chunks/framework.BHvCMIhP.js";const h=JSON.parse('{"title":"介绍 Mochi","description":"","frontmatter":{},"headers":[],"relativePath":"interpreterLearning/03-介绍Mochi.md","filePath":"interpreterLearning/03-介绍Mochi.md","lastUpdated":1778496697000}'),r={name:"interpreterLearning/03-介绍Mochi.md"};function d(e,t,p,i,l,c){return s(),a("div",null,[...t[0]||(t[0]=[o(`<h1 id="介绍-mochi" tabindex="-1">介绍 Mochi <a class="header-anchor" href="#介绍-mochi" aria-label="Permalink to &quot;介绍 Mochi&quot;">​</a></h1><p>每个解释器系列都需要一门玩具语言来承载——《Crafting Interpreters》用 Lox,《Writing An Interpreter in Go》用 Monkey,本系列用 <strong>Mochi</strong>(麻糬,日式糯米团)。<strong>为什么取这个名字</strong>:软、糯、Q弹、能塞各种馅料——动态类型让它&quot;软&quot;,一等公民函数和闭包让它&quot;Q弹&quot;,类和模块让它能&quot;塞各种馅料&quot;。<strong>Mochi 不追求生产可用</strong>,所有&quot;为了简单而省略&quot;的地方都会明确标注「Mochi 这里偷懒了 / 真实语言会怎么做」——但<strong>它要能跑、能 REPL、能在字节码 VM 上比树遍历版本快 5-10 倍</strong>。<strong>这一篇把 Mochi 的语法、设计取舍、路线图一次性钉死,后面 28 篇都在这门语言上叠加,不再改动</strong>。</p><blockquote><p>一句话先记住:<strong>Mochi = 动态类型 + 一等函数 + 闭包 + 类 + 模块</strong>,语法介于 Python 和 JS 之间——<strong>01-19 篇是树遍历版本,20-25 篇切换字节码 VM,26-27 篇加 GC</strong>,一门越长越大的玩具,<strong>不是 30 个孤立 demo</strong>。</p></blockquote><hr><h2 id="一、设计取舍-做什么、不做什么" tabindex="-1">一、设计取舍:做什么、不做什么 <a class="header-anchor" href="#一、设计取舍-做什么、不做什么" aria-label="Permalink to &quot;一、设计取舍:做什么、不做什么&quot;">​</a></h2><p><strong>做的事</strong>(每一项都对应后面某几篇):</p><table tabindex="0"><thead><tr><th>特性</th><th>篇数</th><th>备注</th></tr></thead><tbody><tr><td>动态类型 + 自动内存管理</td><td>11 / 26-27</td><td>不引入静态类型检查,运行时报错</td></tr><tr><td>一等公民函数 + 匿名函数</td><td>14</td><td><code>let f = fn(x){...}</code> 能赋值、传参、返回</td></tr><tr><td>词法作用域 + 闭包</td><td>12, 14</td><td>强制词法,<strong>不做 dynamic scope</strong></td></tr><tr><td>if / while / for / break / continue</td><td>13</td><td><code>for i in 0..10</code> 风格</td></tr><tr><td>类 + 单继承 + super</td><td>16</td><td><strong>不做多重继承,不做原型</strong></td></tr><tr><td>模块系统(<code>import &quot;math&quot;</code>)</td><td>17</td><td>文件即模块,<strong>不做 namespace 嵌套</strong></td></tr><tr><td>try / catch + throw</td><td>13</td><td>异常作为非局部跳转</td></tr><tr><td>字节码 VM</td><td>20-25</td><td>栈式,后面对比寄存器式</td></tr><tr><td>Mark-sweep GC</td><td>26</td><td>简单三色,<strong>不做分代</strong></td></tr></tbody></table><p><strong>坚决不做的事</strong>(留白,真实工业语言才需要):</p><ul><li><strong>并发</strong>——不做协程、不做 channel、不做线程,<strong>Mochi 单线程</strong>(GC 写一遍已经够大了)</li><li><strong>静态类型推导</strong>——不写 Hindley-Milner,18 篇做心智层的对照,<strong>不实现</strong></li><li><strong>泛型 / Trait / 所有权</strong>——这是 Rust 那个量级的工程,<strong>远超玩具语言范畴</strong></li><li><strong>JIT</strong>——28 篇讲心智,但<strong>不在 Mochi 上实现</strong>(JIT 工程量 = 解释器 × 3)</li><li><strong>完整标准库</strong>——只够跑 demo 的 <code>math</code> / <code>string</code> / <code>io</code>,<strong>不要写 Node 那套</strong></li></ul><p><strong>为什么这么砍</strong>:玩具语言的死亡陷阱就是<strong>功能蔓延</strong>——加完类想加 trait,加完 trait 想加泛型,半年没写完一个 GC。<strong>Mochi 锁定 30 篇打完,所有&quot;看起来很想加&quot;的特性都拒绝</strong>。</p><hr><h2 id="二、完整语法速览" tabindex="-1">二、完整语法速览 <a class="header-anchor" href="#二、完整语法速览" aria-label="Permalink to &quot;二、完整语法速览&quot;">​</a></h2><p>整门语言用这一段示例就能讲完:</p><div class="language-mochi vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mochi</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 字面量与变量</span></span>
<span class="line"><span>let x = 10              // 不可变(默认)</span></span>
<span class="line"><span>var y = &quot;hello&quot;         // 可变</span></span>
<span class="line"><span>let arr = [1, 2, 3]</span></span>
<span class="line"><span>let obj = { name: &quot;mochi&quot;, age: 1 }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 函数(一等公民)</span></span>
<span class="line"><span>fn add(a, b) { return a + b }</span></span>
<span class="line"><span>let inc = fn(x) { return x + 1 }   // 匿名函数</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 控制流</span></span>
<span class="line"><span>if x &gt; 0 { print(&quot;pos&quot;) } else { print(&quot;neg&quot;) }</span></span>
<span class="line"><span>while x &gt; 0 { x = x - 1 }</span></span>
<span class="line"><span>for i in 0..10 { print(i) }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 闭包(捕获 by reference)</span></span>
<span class="line"><span>fn make_counter() {</span></span>
<span class="line"><span>  var n = 0</span></span>
<span class="line"><span>  return fn() { n = n + 1; return n }</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>let c = make_counter()</span></span>
<span class="line"><span>print(c())   // 1</span></span>
<span class="line"><span>print(c())   // 2</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 类</span></span>
<span class="line"><span>class Point {</span></span>
<span class="line"><span>  init(x, y) { this.x = x; this.y = y }</span></span>
<span class="line"><span>  distance() { return sqrt(this.x * this.x + this.y * this.y) }</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 继承</span></span>
<span class="line"><span>class ColoredPoint &lt; Point {</span></span>
<span class="line"><span>  init(x, y, color) { super.init(x, y); this.color = color }</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 模块</span></span>
<span class="line"><span>import &quot;math&quot;</span></span>
<span class="line"><span>print(math.sqrt(2))</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 异常</span></span>
<span class="line"><span>try {</span></span>
<span class="line"><span>  risky()</span></span>
<span class="line"><span>} catch (e) {</span></span>
<span class="line"><span>  print(e.message)</span></span>
<span class="line"><span>}</span></span></code></pre></div><p><strong>几个关键决策</strong>:</p><ol><li><strong><code>let</code> 默认不可变,<code>var</code> 可变</strong>——和 Rust / Swift 一致,<strong>鼓励默认不变</strong>(这是过去 20 年语言设计共识)</li><li><strong>大括号 <code>{}</code> 做 block</strong>——不学 Python 的缩进,<strong>Python 缩进让 lexer 复杂 3 倍</strong>(05 篇会讲)</li><li><strong><code>fn</code> 而不是 <code>function</code> / <code>def</code></strong>——3 字符短关键字,<strong>Rust 取 <code>fn</code> 是有道理的</strong></li><li><strong>类用 <code>&lt;</code> 表示继承</strong>——抄 Lox,简洁,<code>class CP &lt; Point</code> 比 <code>extends Point</code> 短</li><li><strong>没有分号</strong>——换行即语句边界,<strong>复杂 case 用 <code>;</code> 兜底</strong>(避免 JS 走过的 ASI 弯路)</li></ol><hr><h2 id="三、跟-lox-monkey-lua-的对比" tabindex="-1">三、跟 Lox / Monkey / Lua 的对比 <a class="header-anchor" href="#三、跟-lox-monkey-lua-的对比" aria-label="Permalink to &quot;三、跟 Lox / Monkey / Lua 的对比&quot;">​</a></h2><p>四门玩具/嵌入式语言放一起,Mochi 的位置一目了然:</p><table tabindex="0"><thead><tr><th>维度</th><th>Lox(CI)</th><th>Monkey(WAIIG)</th><th>Lua</th><th><strong>Mochi</strong></th></tr></thead><tbody><tr><td>宿主语言</td><td>Java / C</td><td>Go</td><td>C</td><td><strong>TypeScript / Rust</strong></td></tr><tr><td>类型系统</td><td>动态</td><td>动态</td><td>动态</td><td><strong>动态</strong></td></tr><tr><td>类支持</td><td>有</td><td>无</td><td>无(table 模拟)</td><td><strong>有(单继承)</strong></td></tr><tr><td>闭包</td><td>有</td><td>有</td><td>有(upvalue)</td><td><strong>有(upvalue)</strong></td></tr><tr><td>模块</td><td>无</td><td>无</td><td><code>require</code></td><td><strong>有(<code>import</code>)</strong></td></tr><tr><td>异常</td><td>无</td><td>无</td><td><code>pcall</code></td><td><strong>有(<code>try/catch</code>)</strong></td></tr><tr><td>树遍历版</td><td>jlox</td><td>Monkey</td><td>无</td><td><strong>01-19 篇</strong></td></tr><tr><td>字节码版</td><td>clox</td><td>(《Writing A Compiler》)</td><td>主版本</td><td><strong>20-25 篇</strong></td></tr><tr><td>GC</td><td>clox 有</td><td>无</td><td>增量 mark-sweep</td><td><strong>简单 mark-sweep(26 篇)</strong></td></tr><tr><td>生产可用</td><td>否</td><td>否</td><td><strong>是</strong></td><td>否</td></tr></tbody></table><p><strong>Mochi 相对其他玩具语言的差异</strong>:</p><ul><li>比 <strong>Lox</strong> 多了模块和异常(更接近现代脚本语言)</li><li>比 <strong>Monkey</strong> 多了类、字节码 VM、GC(Monkey 全树遍历,性能讨论少)</li><li>比 <strong>Lua</strong> 少了协程、寄存器 VM、生产级增量 GC(Lua 是工业语言,本系列只取它的实现思路当参考)</li></ul><p><strong>所以</strong>:<strong>Mochi ≈ Lox 的脚本现代化版本 + Monkey 的章节结构 + Lua 的实现指针</strong>。</p><hr><h2 id="四、路线图" tabindex="-1">四、路线图 <a class="header-anchor" href="#四、路线图" aria-label="Permalink to &quot;四、路线图&quot;">​</a></h2><p>30 篇分六层,Mochi 的形态在第三层第一次跑起来:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01-04  心智层    无 Mochi,只画图、讲设计、搭骨架</span></span>
<span class="line"><span>05-09  前端     Mochi 能 lex / parse,但还不会运行</span></span>
<span class="line"><span>                ↓</span></span>
<span class="line"><span>10-15  树遍历   Mochi 第一次能 print Hello World、跑函数、闭包</span></span>
<span class="line"><span>16-19  进阶语义 Mochi 有类、模块、异常 ── 功能 freeze</span></span>
<span class="line"><span>                ↓ 此后语法和语义不再变化,只换实现</span></span>
<span class="line"><span>20-25  字节码VM Mochi 后端切换:同一份测试用例,速度 ×5-10</span></span>
<span class="line"><span>26-27  GC      Mochi 不再泄漏,能跑大量分配的脚本</span></span>
<span class="line"><span>28-30  剖析    不实现,讲清楚 JIT 心智 + 真实语言对照表</span></span></code></pre></div><p><strong>每一篇都要在 Mochi 仓库提交代码</strong>:</p><ul><li>不动手过的篇不算完成</li><li>每篇都有对应 git tag(<code>v01-overview</code>、<code>v14-closure</code>、<code>v22-vm-loop</code>...)</li><li><code>pnpm test</code> 全过才能打勾</li></ul><p>仓库地址 <code>github.com/.../mochi-lang</code>(实际链接随仓库一起公开)。<strong>16 篇之后语法 freeze</strong>——意味着写到 22 篇调字节码 VM 时,<strong>不会再回去改 Mochi 的语法</strong>,<strong>只是换一个后端</strong>。这是写本系列最关键的纪律:<strong>语言定义一次,实现可以换好几次</strong>。</p><hr><h2 id="五、-偷懒了-的边界" tabindex="-1">五、&quot;偷懒了&quot;的边界 <a class="header-anchor" href="#五、-偷懒了-的边界" aria-label="Permalink to &quot;五、&quot;偷懒了&quot;的边界&quot;">​</a></h2><p>Mochi 是玩具,有些地方会主动砍掉。<strong>所有偷懒处都标注</strong>,避免读者以为这就是真实工业实现:</p><table tabindex="0"><thead><tr><th>地方</th><th>Mochi 偷懒做法</th><th>真实语言会做什么</th></tr></thead><tbody><tr><td>数字类型</td><td>全部 <code>number</code>(JS double)</td><td>Python 分 int / float / bignum,JS 也有 BigInt</td></tr><tr><td>字符串</td><td>UTF-8 byte 数组</td><td>Swift 走 Unicode grapheme cluster</td></tr><tr><td>错误恢复</td><td>parser 遇错就停</td><td>rustc / TS 做 panic mode 继续报多个错</td></tr><tr><td>GC</td><td>单线程 stop-the-world mark-sweep</td><td>V8 / JVM 分代 + 增量 + 并发</td></tr><tr><td>字符串字面量</td><td>不做 string interning</td><td>Java / Python 都 intern 短字符串</td></tr><tr><td>整数溢出</td><td>直接溢出(沿用 JS 行为)</td><td>Rust debug panic、Python bignum 自动扩展</td></tr><tr><td>闭包捕获</td><td>直接捕获环境引用</td><td>V8 做逃逸分析,多数 closure 在栈上</td></tr><tr><td>模块循环依赖</td><td>直接报错</td><td>CommonJS 返回半初始化对象,ESM 用占位符</td></tr><tr><td>浮点 NaN / Infinity</td><td>沿用 JS 行为</td><td>Python 区分 NaN / Inf 的语义边界</td></tr></tbody></table><p><strong>读完每一篇,你应该清楚三件事</strong>:</p><ul><li>这一篇做了什么</li><li><strong>省略了什么</strong>(下一句就接「Mochi 这里偷懒了」)</li><li><strong>工业级是怎么做的</strong>(给具体文件路径或类名)</li></ul><p>这三件事做到了,这门玩具语言就<strong>值得花 30 篇的时间</strong>。</p><hr><p>下一篇:<code>04-项目骨架与REPL.md</code>,把 Mochi 仓库的目录结构、测试驱动框架、错误位置追踪、REPL 主循环搭起来——<strong>一开始就把基建搭对,后面 25 篇不用回头改</strong>。</p>`,39)])])}const u=n(r,[["render",d]]);export{h as __pageData,u as default};
